import React from 'react';
import { LayoutGrid, Github } from 'lucide-react';

function Footer() {
  return (
    <footer className="w-full bg-black/40 border-t border-white/5 py-8 mt-auto backdrop-blur-md relative z-10">
      <div className="max-w-7xl mx-auto px-6 flex flex-col md:flex-row justify-between items-center gap-4">
        
        <div className="flex items-center gap-2 text-white opacity-80">
          <LayoutGrid className="w-5 h-5 text-indigo-400" />
          <span className="font-bold tracking-tight">CampusCanvas</span>
        </div>
        
        <div className="text-gray-500 text-sm text-center md:text-left">
          © 2026 Naipunnya Institute of Management and Information Technology.<br />
          <span className="text-xs">Built by Mebin, Glodin, Alen & Greeshma</span>
        </div>

        <div className="flex gap-4">
          <a href="#" className="w-10 h-10 rounded-full bg-white/5 flex items-center justify-center text-gray-400 hover:text-white hover:bg-white/10 transition border border-white/5">
            <Github className="w-5 h-5" />
          </a>
        </div>
        
      </div>
    </footer>
  );
}

export default Footer;
